import axios from 'axios';

const setAxiosUrl = axios.create({ baseURL: 'http://54.241.70.63:3300/' });
// const setAxiosUrl = axios.create({ baseURL: 'http://165.232.187.214:3300/' });
// const setAxiosUrl = axios.create({ baseURL: 'http://192.168.40.108:3300/' });

setAxiosUrl.interceptors.request.use((req) => {
  if (localStorage.getItem("token")) {
      req.headers.authorization = `Bearer ${localStorage.getItem("token")}`
  }
  return req;
})

export const signUp = async (data) => {
  try {
    const res = await setAxiosUrl.post('/users/sign-up', data);
    return res.data;
  } catch (error) {
    console.log('error', error);
    return error;
  }
};

